    <script>
        // Buggy Implementation
        let buggyProgress = 0;  // Shared state variable

        function updateBuggyProgressBar() {
            const fillElement = document.getElementById('buggy-progress-fill');
            const textElement = document.getElementById('buggy-progress-text');
            fillElement.style.width = Math.min(buggyProgress, 100) + '%';
