        // Helper function to simulate a delay (using setTimeout with Promises)
        function delay(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        }

        // Buggy implementation variables
        let buggyProgress = 0;  // Shared state for buggy demo

        async function buggyUpdate(amount) {
            let current = buggyProgress;  // Read the current value
            await delay(100);  // Simulate async work; this allows race conditions
            buggyProgress = current + amount;  // Write the updated value
            document.getElementById('buggyProgressBar').value = buggyProgress;
            document.getElementById('buggyStatus').textContent = `Status: Updated to ${buggyProgress}%`;
            console.log(`Buggy progress updated to: ${buggyProgress}%`);
