        function startBuggy() {
            buggyProgress = 0;  // Reset shared state
            document.getElementById('buggyProgressBar').value = 0;
            document.getElementById('buggyStatus').textContent = 'Status: Running...';

            // Launch multiple concurrent tasks
            Promise.all([
                buggyUpdate(20),  // Task 1: Add 20
                buggyUpdate(30),  // Task 2: Add 30
                buggyUpdate(40)   // Task 3: Add 40
            ]).then(() => {
                document.getElementById('buggyStatus').textContent = `Status: Completed (final: ${buggyProgress}%) - May show bugs like skipped values or incorrect total!`;
                console.log('Buggy tasks completed');
            });
            // Due to concurrency, race conditions can occur, e.g., all tasks might read buggyProgress as 0 and overwrite each other.
        }

        // Fixed implementation variables
        let fixedProgress = 0;  // Shared state for fixed demo
        let queue = Promise.resolve();  // Promise-based queue for synchronization

        function enqueue(fn) {
            queue = queue.then(fn);  // Chain the function to the queue
            return queue;  // Return the promise for the next item
        }

        async function fixedUpdate(amount) {
            await enqueue(async () => {
                let current = fixedProgress;  // Read the current value
                await delay(100);  // Simulate async work
                fixedProgress = current + amount;  // Write the updated value
                document.getElementById('fixedProgressBar').value = fixedProgress;
                document.getElementById('fixedStatus').textContent = `Status: Updated to ${fixedProgress}%`;
                console.log(`Fixed progress updated to: ${fixedProgress}%`);
            });
        }

        function startFixed() {
            fixedProgress = 0;  // Reset shared state
            document.getElementById('fixedProgressBar').value = 0;
            document.getElementById('fixedStatus').textContent = 'Status: Running...';

            // Launch multiple concurrent tasks, but they will be processed sequentially via the queue
            fixedUpdate(20);  // Task 1: Add 20
            fixedUpdate(30);  // Task 2: Add 30
            fixedUpdate(40);  // Task 3: Add 40

            // The queue ensures that even though these are called concurrently, updates happen one at a time.
            queue.then(() => {
                document.getElementById('fixedStatus').textContent = `Status: Completed (final: ${fixedProgress}%) - No bugs!`;
                console.log('Fixed tasks completed');
            });
