        function enqueueFixedUpdate(amount) {
            fixedQueue = fixedQueue.then(() => {
                return new Promise(resolve => {
                    setTimeout(() => {
                        fixedProgress += amount;  // Safe increment
                        updateFixedBar();
                        resolve();
                    }, Math.random() * 500);  // Random delay, but processed in order
